from collections import defaultdict, deque

def detect_circular_delegation(agent_history):
    graph = defaultdict(list)
    for call in agent_history:
        if 'delegation_to' in call:
            graph[call['agent_id']].append(call['delegation_to'])

    for agent in graph:
        visited = set()
        stack = deque([agent])
        while stack:
            node = stack.pop()
            if node in visited:
                return True, f"Circular dependency detected: {agent} -> {node}"
            visited.add(node)
            stack.extend(n for n in graph[node] if n not in visited)
    return False, 'No circular dependencies'

def detect_token_spikes(api_calls):
    costs = []
    for call in api_calls:
        tokens = call.get('input_tokens', 0) + call.get('output_tokens', 0)
        costs.append(tokens)

    if len(costs) < 10:
        return False, 0

    recent_avg = sum(costs[-5:]) / 5
    prev_avg = sum(costs[-10:-5]) / 5
    spike_ratio = recent_avg / prev_avg if prev_avg > 0 else 0

    if spike_ratio > 3:
        return True, f"Token spike detected: {spike_ratio:.1f}x increase"
    return False, 0

MODEL_COSTS = {
    'gemini-1.5-flash': 0.35,
    'gemini-1.5-pro': 3.50
}

def detect_model_overkill(calls):
    overkill_count = 0
    for call in calls:
        model = call.get('model')
        task_tokens = call.get('input_tokens', 0)

        if model == 'gemini-1.5-pro' and task_tokens < 500:
            overkill_count += 1
            cost_savings = (MODEL_COSTS['gemini-1.5-pro'] - MODEL_COSTS['gemini-1.5-flash']) * (task_tokens / 1000)

    return overkill_count > 0, f"{overkill_count} pro model calls could use flash (save ~${cost_savings:.2f}/K tokens)"

