from google.adk import Agent, agent

@agent
class CostOptimizedAgent(Agent):
    def __init__(self):
        self.delegation_count = 0
        self.max_delegations = 3

    async def execute(self, request):
        if self.delegation_count >= self.max_delegations:
            return {"error": "Max delegation depth exceeded", "response": "Direct answer"}

        self.delegation_count += 1
        result = await super().execute(request)
        self.delegation_count -= 1
        return result

from google.adk import before_agent_callback

@before_agent_callback
def prune_conversation_state(session):
    if len(session.history) > 20:
        # Keep last 10 exchanges + first 2 for context
        session.history = session.history[:2] + session.history[-10:]

    # Remove redundant system messages
    unique_history = []
    seen_roles = set()
    for msg in reversed(session.history):
        role_key = f"{msg.role}:{msg.content[:50]}"
        if role_key not in seen_roles:
            unique_history.insert(0, msg)
            seen_roles.add(role_key)
        if len(unique_history) >= 15:
            break
    session.history = unique_history
    return session
